import { filterXSS } from 'xss';

const FILTER_OPTIONS = {
  whiteList: {},
  stripIgnoreTag: true,
  stripIgnoreTagBody: ['*'],
};

/**
 * Sanitizes the value received removing XSS and truncating at first quote
 */
export function sanitizeValue(value: string) {
  const sanitized = filterXSS(value, FILTER_OPTIONS);

  if (!sanitized) {
    return '';
  }

  const singleQuoteIndex = sanitized.indexOf("'");
  const doubleQuoteIndex = sanitized.indexOf('"');

  if (singleQuoteIndex < 0 && doubleQuoteIndex < 0) {
    return sanitized;
  }

  let firstQuoteIndex =
    singleQuoteIndex < 0 ? doubleQuoteIndex : singleQuoteIndex;

  if (doubleQuoteIndex !== -1 && singleQuoteIndex !== doubleQuoteIndex) {
    firstQuoteIndex = Math.min(firstQuoteIndex, doubleQuoteIndex);
  }

  return sanitized.substring(0, firstQuoteIndex) || '';
}
